const OAuthConfig = {
  clientId: 'YOUR_CLIENT_ID',
  redirectUri: window.location.origin + '/callback',
  authorizationEndpoint: 'https://oauth-provider.com/oauth/authorize',
  tokenEndpoint: 'https://oauth-provider.com/oauth/token',
  scope: 'read write',
  state: null,
  codeVerifier: null
};

function generateRandomString(length) {
  const charset = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  const randomValues = new Uint8Array(length);
  crypto.getRandomValues(randomValues);
  return Array.from(randomValues)
    .map(v => charset[v % charset.length])
    .join('');
}

async function sha256(plain) {
  const encoder = new TextEncoder();
  const data = encoder.encode(plain);
  const hash = await crypto.subtle.digest('SHA-256', data);
  return hash;
}

function base64urlencode(buffer) {
  const bytes = new Uint8Array(buffer);
  let str = '';
  bytes.forEach(byte => {
    str += String.fromCharCode(byte);
  });
  return btoa(str)
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '');
}

async function generateCodeChallenge(codeVerifier) {
  const hashed = await sha256(codeVerifier);
  return base64urlencode(hashed);
}

async function initiateOAuthFlow() {
  const state = generateRandomString(32);
  const codeVerifier = generateRandomString(128);
  const codeChallenge = await generateCodeChallenge(codeVerifier);

  sessionStorage.setItem('oauth_state', state);
  sessionStorage.setItem('oauth_code_verifier', codeVerifier);

  const params = new URLSearchParams({
    response_type: 'code',
    client_id: OAuthConfig.clientId,
    redirect_uri: OAuthConfig.redirectUri,
    scope: OAuthConfig.scope,
    state: state,
    code_challenge: codeChallenge,
    code_challenge_method: 'S256'
  });

  window.location.href = `${OAuthConfig.authorizationEndpoint}?${params.toString()}`;
}

async function handleCallback() {
  const urlParams = new URLSearchParams(window.location.search);
  const code = urlParams.get('code');
  const state = urlParams.get('state');
  const error = urlParams.get('error');

  if (error) {
    console.error('OAuth error:', error);
    throw new Error(`OAuth error: ${error}`);
  }

  const storedState = sessionStorage.getItem('oauth_state');
  if (!state || state !== storedState) {
    throw new Error('Invalid state parameter - possible CSRF attack');
  }

  if (!code) {
    throw new Error('No authorization code received');
  }

  const codeVerifier = sessionStorage.getItem('oauth_code_verifier');
  if (!codeVerifier) {
    throw new Error('Code verifier not found');
  }

  sessionStorage.removeItem('oauth_state');
  sessionStorage.removeItem('oauth_code_verifier');

  await exchangeCodeForToken(code, codeVerifier);
}

async function exchangeCodeForToken(code, codeVerifier) {
  const params = new URLSearchParams({
    grant_type: 'authorization_code',
    code: code,
    redirect_uri: OAuthConfig.redirectUri,
    client_id: OAuthConfig.clientId,
    code_verifier: codeVerifier
  });

  try {
    const response = await fetch(OAuthConfig.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: params.toString()
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(`Token exchange failed: ${errorData.error || response.statusText}`);
    }

    const tokenData = await response.json();
    storeTokens(tokenData);
    return tokenData;
  } catch (error) {
    console.error('Token exchange error:', error);
    throw error;
  }
}

function storeTokens(tokenData) {
  const expiresAt = Date.now() + (tokenData.expires_in * 1000);
  
  localStorage.setItem('access_token', tokenData.access_token);
  localStorage.setItem('token_expires_at', expiresAt.toString());
  
  if (tokenData.refresh_token) {
    localStorage.setItem('refresh_token', tokenData.refresh_token);
  }
  
  if (tokenData.id_token) {
    localStorage.setItem('id_token', tokenData.id_token);
  }
}

function getAccessToken() {
  return localStorage.getItem('access_token');
}

function isTokenExpired() {
  const expiresAt = localStorage.getItem('token_expires_at');
  if (!expiresAt) return true;
  
  const bufferTime = 5 * 60 * 1000;
  return Date.now() >= (parseInt(expiresAt) - bufferTime);
}

async function refreshAccessToken() {
  const refreshToken = localStorage.getItem('refresh_token');
  
  if (!refreshToken) {
    throw new Error('No refresh token available');
  }

  const params = new URLSearchParams({
    grant_type: 'refresh_token',
    refresh_token: refreshToken,
    client_id: OAuthConfig.clientId
  });

  try {
    const response = await fetch(OAuthConfig.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: params.toString()
    });

    if (!response.ok) {
      clearTokens();
      throw new Error('Token refresh failed');
    }

    const tokenData = await response.json();
    storeTokens(tokenData);
    return tokenData;
  } catch (error) {
    console.error('Token refresh error:', error);
    clearTokens();
    throw error;
  }
}

async function getValidAccessToken() {
  if (isTokenExpired()) {
    try {
      await refreshAccessToken();
    } catch (error) {
      return null;
    }
  }
  return getAccessToken();
}

async function makeAuthenticatedRequest(url, options = {}) {
  const token = await getValidAccessToken();
  
  if (!token) {
    throw new Error('No valid access token available');
  }

  const headers = {
    ...options.headers,
    'Authorization': `Bearer ${token}`
  };

  const response = await fetch(url, {
    ...options,
    headers
  });

  if (response.status === 401) {
    try {
      await refreshAccessToken();
      const newToken = getAccessToken();
      headers['Authorization'] = `Bearer ${newToken}`;
      
      return await fetch(url, {
        ...options,
        headers
      });
    } catch (error) {
      clearTokens();
      throw new Error('Authentication failed');
    }
  }

  return response;
}

function clearTokens() {
  localStorage.removeItem('access_token');
  localStorage.removeItem('refresh_token');
  localStorage.removeItem('id_token');
  localStorage.removeItem('token_expires_at');
}

function logout() {
  clearTokens();
  window.location.href = '/';
}

function isAuthenticated() {
  const token = getAccessToken();
  return token !== null && !isTokenExpired();
}

const App = {
  init() {
    this.render();
    this.attachEventListeners();
    
    if (window.location.pathname === '/callback') {
      this.handleOAuthCallback();
    }
  },

  render() {
    const app = document.getElementById('app');
    
    if (window.location.pathname === '/callback') {
      app.innerHTML = `
        <div class="container">
          <h1>Processing authentication...</h1>
          <div class="loader"></div>
        </div>
      `;
      return;
    }

    if (isAuthenticated()) {
      app.innerHTML = `
        <div class="container">
          <h1>Welcome!</h1>
          <p>You are authenticated.</p>
          <button id="logoutBtn">Logout</button>
          <button id="testApiBtn">Test API Request</button>
          <div id="apiResult"></div>
        </div>
      `;
    } else {
      app.innerHTML = `
        <div class="container">
          <h1>OAuth 2.0 Authentication</h1>
          <p>Please login to continue</p>
          <button id="loginBtn">Login with OAuth</button>
        </div>
      `;
    }
  },

  attachEventListeners() {
    const loginBtn = document.getElementById('loginBtn');
    const logoutBtn = document.getElementById('logoutBtn');
    const testApiBtn = document.getElementById('testApiBtn');

    if (loginBtn) {
      loginBtn.addEventListener('click', () => {
        initiateOAuthFlow();
      });
    }

    if (logoutBtn) {
      logoutBtn.addEventListener('click', () => {
        logout();
        this.render();
      });
    }

    if (testApiBtn) {
      testApiBtn.addEventListener('click', async () => {
        await this.testApiRequest();
      });
    }
  },

  async handleOAuthCallback() {
    try {
      await handleCallback();
      window.history.replaceState({}, document.title, '/');
      this.render();
      this.attachEventListeners();
    } catch (error) {
      console.error('OAuth callback error:', error);
      document.getElementById('app').innerHTML = `
        <div class="container">
          <h1>Authentication Error</h1>
          <p>${error.message}</p>
          <button onclick="window.location.href='/'">Go Home</button>
        </div>
      `;
    }
  },

  async testApiRequest() {
    const resultDiv = document.getElementById('apiResult');
    resultDiv.innerHTML = '<p>Loading...</p>';

    try {
      const response = await makeAuthenticatedRequest('https://api.example.com/user');
      const data = await response.json();
      resultDiv.innerHTML = `<pre>${JSON.stringify(data, null, 2)}</pre>`;
    } catch (error) {
      resultDiv.innerHTML = `<p style="color: red;">Error: ${error.message}</p>`;
    }
  }
};

if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', () => App.init());
} else {
  App.init();
}

